import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  Box, 
  Container, 
  Grid, 
  Paper, 
  Typography, 
  Button, 
  Card, 
  CardContent, 
  Divider,
  List,
  ListItem,
  ListItemText,
  ListItemAvatar,
  Avatar,
  CircularProgress,
  Alert
} from '@mui/material';
import {
  AccountBalanceWallet,
  Send,
  Chat,
  SwapHoriz,
  Assessment,
  ArrowUpward,
  ArrowDownward,
  Error
} from '@mui/icons-material';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  const { currentUser, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [wallets, setWallets] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [error, setError] = useState(null);
  const [totalBalance, setTotalBalance] = useState(0);

  useEffect(() => {
    const fetchDashboardData = async () => {
      setLoading(true);
      setError(null);

      try {
        // Fetch wallets
        try {
          console.log('Fetching wallet data...');
          let walletData = [];

          // Try user-specific wallet endpoint if we have a user ID
          if (currentUser && currentUser.id) {
            try {
              const walletsResponse = await api.get(`/wallet/${currentUser.id}`);
              console.log('User specific wallet response:', walletsResponse.data);
              if (Array.isArray(walletsResponse.data)) {
                walletData = walletsResponse.data;
              } else {
                // It might be a single wallet object
                walletData = [walletsResponse.data];
              }
            } catch (userWalletErr) {
              console.warn('Could not fetch user-specific wallet, trying general endpoint:', userWalletErr);
            }
          }

          // If we couldn't get user wallets, try the general endpoint
          if (walletData.length === 0) {
            const generalWalletResponse = await api.get('/wallet/');
            console.log('General wallet response:', generalWalletResponse.data);
            if (Array.isArray(generalWalletResponse.data)) {
              walletData = generalWalletResponse.data;
            } else if (generalWalletResponse.data) {
              walletData = [generalWalletResponse.data];
            }
          }

          setWallets(walletData || []);

          // Calculate total balance across all wallets
          const total = (walletData || []).reduce((sum, wallet) => 
            sum + parseFloat(wallet.fiat_balance || wallet.balance || 0), 0);
          setTotalBalance(total);

        } catch (walletErr) {
          console.error('Error fetching wallets:', walletErr);
          // Don't set an error here, just use empty wallet data
          setWallets([]);
          setTotalBalance(0);
        }

        // Fetch recent transactions
        try {
          console.log('Fetching transaction data...');
          let transactionsData = [];

          // Try user-specific transactions first
          if (currentUser && currentUser.id) {
            try {
              const userTxResponse = await api.get(`/transaction/user/${currentUser.id}`);
              console.log('User transactions response:', userTxResponse.data);
              if (Array.isArray(userTxResponse.data)) {
                transactionsData = userTxResponse.data;
              } else if (userTxResponse.data && Array.isArray(userTxResponse.data.transactions)) {
                transactionsData = userTxResponse.data.transactions;
              }
            } catch (userTxErr) {
              console.warn('Could not fetch user transactions, trying history endpoint:', userTxErr);

              try {
                const historyResponse = await api.get(`/transaction/${currentUser.id}/history`);
                console.log('Transaction history response:', historyResponse.data);
                transactionsData = [
                  ...(historyResponse.data?.sent_transactions || []),
                  ...(historyResponse.data?.received_transactions || [])
                ];
              } catch (historyErr) {
                console.warn('Could not fetch transaction history:', historyErr);
              }
            }
          }

          // If we still don't have transactions, try the general endpoint
          if (transactionsData.length === 0) {
            const generalTxResponse = await api.get('/transaction/');
            console.log('General transaction response:', generalTxResponse.data);
            if (Array.isArray(generalTxResponse.data)) {
              transactionsData = generalTxResponse.data;
            } else if (generalTxResponse.data && Array.isArray(generalTxResponse.data.transactions)) {
              transactionsData = generalTxResponse.data.transactions;
            }
          }

          // Process and format the transaction data
          const processedTransactions = transactionsData.map(tx => ({
            ...tx,
            formattedAmount: formatCurrency(tx.amount || tx.source_amount, tx.currency || 'USD'),
            formattedDate: tx.timestamp ? formatDate(tx.timestamp) : 'N/A',
            type: determineTransactionType(tx)
          }));

          setTransactions(processedTransactions || []);

        } catch (txErr) {
          console.error('Error fetching transactions:', txErr);
          // Don't set an error here, just use empty transaction data
          setTransactions([]);
        }
      } catch (err) {
        console.error('Error fetching dashboard data:', err);
        setError('Failed to load dashboard data. Please try again.');
      } finally {
        setLoading(false);
      }
    };

    if (isAuthenticated) {
      fetchDashboardData();
    } else {
      setLoading(false);
    }
  }, [isAuthenticated, currentUser]);

  const determineTransactionType = (transaction) => {
    if (transaction.type) return transaction.type;
    if (transaction.transaction_type) return transaction.transaction_type;

    // If no explicit type, try to infer from other properties
    if (transaction.from_wallet_id && transaction.to_wallet_id) {
      return 'TRANSFER';
    } else if (transaction.to_wallet_id) {
      return 'DEPOSIT';
    } else if (transaction.from_wallet_id) {
      return 'WITHDRAWAL';
    }

    return 'UNKNOWN';
  };

  const formatCurrency = (amount, currency = 'USD') => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency
    }).format(amount || 0);
  };

  const formatDate = (dateString) => {
    const options = { year: 'numeric', month: 'short', day: 'numeric' };
    return new Date(dateString).toLocaleDateString('en-US', options);
  };

  const getTransactionIcon = (type) => {
    const typeUpper = String(type).toUpperCase();
    if (typeUpper === 'DEPOSIT' || typeUpper === 'RECEIVE') return <ArrowDownward color="success" />;
    if (typeUpper === 'WITHDRAWAL' || typeUpper === 'SEND') return <ArrowUpward color="error" />;
    return <SwapHoriz color="primary" />;
  };

  if (!isAuthenticated) {
    return (
      <Box display="flex" flexDirection="column" justifyContent="center" alignItems="center" minHeight="80vh">
        <Error sx={{ fontSize: 60, color: 'error.main', mb: 2 }} />
        <Typography variant="h5" gutterBottom>
          Authentication Required
        </Typography>
        <Typography variant="body1" color="text.secondary" align="center" sx={{ mb: 3, maxWidth: 500 }}>
          Please log in to view your dashboard and access TerraFlow features.
        </Typography>
        <Button 
          variant="contained" 
          onClick={() => navigate('/login')}
        >
          Go to Login
        </Button>
      </Box>
    );
  }

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Grid container spacing={3}>
        {/* Welcome Section */}
        <Grid item xs={12}>
          <Paper sx={{ p: 3, display: 'flex', flexDirection: 'column' }}>
            <Typography variant="h4" gutterBottom>
              Welcome, {currentUser?.username || 'User'}
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Here's an overview of your account
            </Typography>
          </Paper>
        </Grid>

        {error && (
          <Grid item xs={12}>
            <Alert severity="error">{error}</Alert>
          </Grid>
        )}

        {/* Total Balance */}
        <Grid item xs={12} md={4}>
          <Paper 
            sx={{ 
              p: 2, 
              display: 'flex', 
              flexDirection: 'column',
              backgroundColor: 'primary.main',
              color: 'white'
            }}
          >
            <Typography variant="h6" gutterBottom>
              Total Balance
            </Typography>
            <Typography variant="h3" component="div" sx={{ fontWeight: 'bold' }}>
              {formatCurrency(totalBalance)}
            </Typography>
            <Typography variant="body2" sx={{ mt: 1 }}>
              Across all wallets
            </Typography>
          </Paper>
        </Grid>

        {/* Quick Actions */}
        <Grid item xs={12} md={8}>
          <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column' }}>
            <Typography variant="h6" gutterBottom>
              Quick Actions
            </Typography>
            <Grid container spacing={2} sx={{ mt: 1 }}>
              <Grid item xs={6} sm={3}>
                <Button 
                  variant="outlined" 
                  fullWidth 
                  startIcon={<Send />} 
                  sx={{ p: 1 }}
                  onClick={() => navigate('/send')}
                >
                  Send
                </Button>
              </Grid>
              <Grid item xs={6} sm={3}>
                <Button 
                  variant="outlined" 
                  fullWidth 
                  startIcon={<AccountBalanceWallet />} 
                  sx={{ p: 1 }}
                  onClick={() => navigate('/wallets')}
                >
                  Wallets
                </Button>
              </Grid>
              <Grid item xs={6} sm={3}>
                <Button 
                  variant="outlined" 
                  fullWidth 
                  startIcon={<Chat />} 
                  sx={{ p: 1 }}
                  onClick={() => navigate('/nl-interface')}
                >
                  Ask AI
                </Button>
              </Grid>
              <Grid item xs={6} sm={3}>
                <Button 
                  variant="outlined" 
                  fullWidth 
                  startIcon={<Assessment />} 
                  sx={{ p: 1 }}
                  onClick={() => navigate('/analytics')}
                >
                  Analytics
                </Button>
              </Grid>
            </Grid>
          </Paper>
        </Grid>

        {/* Wallets Section */}
        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column' }}>
            <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
              <Typography variant="h6">Your Wallets</Typography>
              <Button 
                size="small" 
                onClick={() => navigate('/wallets')}
              >
                View All
              </Button>
            </Box>

            {wallets.length === 0 ? (
              <Box textAlign="center" py={3}>
                <Typography variant="body1" color="text.secondary">
                  You don't have any wallets yet.
                </Typography>
                <Button 
                  variant="contained" 
                  startIcon={<AccountBalanceWallet />} 
                  sx={{ mt: 2 }}
                  onClick={() => navigate('/wallets')}
                >
                  Manage Wallets
                </Button>
              </Box>
            ) : (
              <Box>
                {wallets.slice(0, 3).map((wallet) => (
                  <Card key={wallet.id} sx={{ mb: 2 }}>
                    <CardContent>
                      <Typography variant="subtitle1" gutterBottom>
                        {wallet.name || `Wallet ${wallet.id}`}
                      </Typography>
                      <Typography variant="h5" component="div">
                        {formatCurrency(wallet.fiat_balance || wallet.balance, wallet.currency)}
                      </Typography>
                      <Typography color="text.secondary" sx={{ fontSize: 14, mt: 1 }}>
                        {wallet.wallet_address || wallet.address || 'No address available'}
                      </Typography>
                    </CardContent>
                  </Card>
                ))}
              </Box>
            )}
          </Paper>
        </Grid>

        {/* Recent Transactions */}
        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column' }}>
            <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
              <Typography variant="h6">Recent Transactions</Typography>
              <Button 
                size="small" 
                onClick={() => navigate('/transactions')}
              >
                View All
              </Button>
            </Box>

            {transactions.length === 0 ? (
              <Box textAlign="center" py={3}>
                <Typography variant="body1" color="text.secondary">
                  No transactions found.
                </Typography>
                <Button 
                  variant="contained" 
                  startIcon={<Send />} 
                  sx={{ mt: 2 }}
                  onClick={() => navigate('/send')}
                >
                  Send Money
                </Button>
              </Box>
            ) : (
              <List>
                {transactions.slice(0, 5).map((transaction) => (
                  <React.Fragment key={transaction.id}>
                    <ListItem alignItems="flex-start">
                      <ListItemAvatar>
                        <Avatar sx={{ bgcolor: 'background.paper' }}>
                          {getTransactionIcon(transaction.type || 'TRANSFER')}
                        </Avatar>
                      </ListItemAvatar>
                      <ListItemText
                        primary={
                          <Typography variant="subtitle2">
                            {transaction.type || 'Transfer'} - {transaction.formattedAmount || formatCurrency(transaction.source_amount || transaction.amount)}
                          </Typography>
                        }
                        secondary={
                          <>
                            <Typography component="span" variant="body2" color="text.primary">
                              {transaction.status || 'Completed'}
                            </Typography>
                            {' — '}{transaction.formattedDate || formatDate(transaction.timestamp || new Date())}
                          </>
                        }
                      />
                    </ListItem>
                    <Divider variant="inset" component="li" />
                  </React.Fragment>
                ))}
              </List>
            )}
          </Paper>
        </Grid>
      </Grid>
    </Container>
  );
};

export default Dashboard;
